// Send an email via Mailgun.
send({
  // Sender address. Use a domain you've verified in Mailgun.
  from: `OpenFn <noreply@${$.configuration.domain}>`,
  // Recipient (string, or array for multiple).
  to: $.data.recipient,
  subject: $.data.subject,
  // Plain-text and / or HTML bodies.
  text: $.data.body,
  // html: `<p>${$.data.body}</p>`,
});
